'use strict'

const assert = require('node:assert')
const { H2CClient } = require('/workspace/undici')

async function verifiesCustomConnector () {
  const customError = new Error('custom connector used')
  let called = false

  const client = new H2CClient('http://localhost:3000', {
    connect (opts, callback) {
      called = true
      assert.strictEqual(opts.allowH2, true)
      console.log('CUSTOM_CONNECT_CALLED')
      callback(customError, null)
    }
  })

  try {
    await assert.rejects(
      client.request({ path: '/', method: 'GET' }),
      (err) => err === customError
    )
  } finally {
    await client.close().catch(() => {})
  }

  assert.strictEqual(called, true)
}

function verifiesInvalidConnectorRejected () {
  assert.throws(() => new H2CClient('http://localhost:3000', { connect: 'invalid' }), {
    message: 'connect must be a function or an object'
  })
  console.log('INVALID_CONNECT_REJECTED')
}

async function main () {
  await verifiesCustomConnector()
  verifiesInvalidConnectorRejected()
}

main().catch(err => {
  console.error(err)
  process.exitCode = 1
})
